import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjButton } from "./OjButton";
export { OjButton };

/**
 * Create an instance of [[OjButton]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojButton(driver, By.id('my-oj-button'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojButton(driver: DriverLike, by: By): Promise<OjButton> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjButton
  if (!(webEl instanceof OjButton)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-button>`);
  }
  return webEl;
}

register("oj-button", OjButton);
